module DFlipFlop (
    input wire clk,
    input wire reset,
    input wire D,
    output reg Q
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            Q <= 0;
        end else begin
            Q <= D;
        end
    end
endmodule
